// 1. Alpaca format: instruction + optional input + output
{
  "instruction": "Summarise the following paragraph in one sentence.",
  "input": "The Amazon rainforest, often referred to as...",
  "output": "The Amazon rainforest is the world's largest tropical forest."
}

// 2. ShareGPT / ChatML format: multi-turn conversation
{
  "conversations": [
    {"from": "system", "value": "You are a helpful assistant."},
    {"from": "human",  "value": "What is the capital of France?"},
    {"from": "gpt",    "value": "The capital of France is Paris."},
    {"from": "human",  "value": "And of Germany?"},
    {"from": "gpt",    "value": "The capital of Germany is Berlin."}
  ]
}

// 3. Simple prompt-completion (used by OpenAI fine-tuning API)
{
  "prompt": "Classify the sentiment: I love this product!\n\nSentiment:",
  "completion": " positive"
}
